+        let stats = search.stats();
+        assert_eq!(stats.pop_size, 4);
+        assert!(stats.max_fitness >= stats.min_fitness);
+        assert!(stats.mean_fitness >= stats.min_fitness);
+        assert!(stats.mean_fitness <= stats.max_fitness);
