+    #[test]
+    fn query_signature_deterministic() {
+        let query = vec![0.1, 0.2, 0.3, 0.4];
+        let sig1 = QuerySignature::from_query(&query);
+        let sig2 = QuerySignature::from_query(&query);
+        assert_eq!(sig1, sig2);
