+    #[test]
+    fn negative_cache_reaches_threshold() {
+        let mut cache = NegativeCache::new(3, Duration::from_secs(60), 1000);
+        let sig = QuerySignature::from_query(&[0.1, 0.2]);
+        cache.record_degenerate(sig);
