+        assert!(cache.record_degenerate(sig)); // 3rd hit = blacklisted.
+        assert!(cache.is_blacklisted(&sig));
+    }
+
+    #[test]
+    fn negative_cache_max_entries() {
+        let mut cache = NegativeCache::new(100, Duration::from_secs(60), 5);
