+#[test]
+fn resource_budget_clamping() {
+    let clamped = ResourceBudget {
+        max_time_secs: 99999, max_tokens: 99999999,
+        max_cost_microdollars: 99999999,
+        max_tool_calls: 65535, max_external_writes: 65535,
